package com.restaurantcraft.screen; import com.restaurantcraft.menu.CookingDeviceMenu; import net.minecraft.client.gui.GuiGraphics; import net.minecraft.client.gui.screens.inventory.AbstractContainerScreen; import net.minecraft.network.chat.Component; import net.minecraft.world.entity.player.Inventory; public class CookingDeviceScreen extends AbstractContainerScreen<CookingDeviceMenu>{ public CookingDeviceScreen(CookingDeviceMenu m, Inventory i, Component t){super(m,i,t);} public void render(GuiGraphics g,int mx,int my,float pt){renderBackground(g);super.render(g,mx,my,pt);renderTooltip(g,mx,my);} protected void renderBg(GuiGraphics g,float p,int mx,int my){g.fill(leftPos,topPos,leftPos+imageWidth,topPos+imageHeight,0xCC303030); g.drawString(font,title,leftPos+8,topPos+8,0xFFFFFF,false);} }
